n_hex = "" 

e_hex = "10001" 

sig_hex = "" 

expected_hash = "2086440c0eaa3387cea8264d8fb5d54238aaa590d0641c81b3761be0399452aa"

n = int(n_hex, 16)
e = int(e_hex, 16)
S = int(sig_hex, 16)

M_prime = pow(S, e, n)

M_prime_hex = hex(M_prime)[2:]

print("KẾT QUẢ GIẢI MÃ CHỮ KÍ")
print(M_prime_hex)

extracted_hash = M_prime_hex[-64:]

print("\n--- KIỂM TRA MÃ BĂM ---")
print("Mã băm trích xuất từ chữ ký :", extracted_hash)
print("Mã băm tự tính (Expected)   :", expected_hash)

if extracted_hash == expected_hash:
    print("\n=> KẾT LUẬN: XÁC MINH THÀNH CÔNG! Chữ ký hoàn toàn hợp lệ.")
else:
    print("\n=> KẾT LUẬN: XÁC MINH THẤT BẠI! Chữ ký không hợp lệ.")
